import { useEffect, useState } from "react";
import api from "../api";

/** ========= Config ========= **/
const PAGE_SIZE = 10;
const ROLES = ["ADMIN", "SALES", "ACCOUNTANT"];   // vẫn dùng cho bộ lọc ở list
const STATUSES = ["ACTIVE", "INACTIVE"];

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return { list: d?.content || [], pages: typeof d?.totalPages === "number" ? d.totalPages : 1 };
}

/** debounce nhỏ cho ô tìm kiếm */
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

function emptyForm() {
    return {
        username: "",
        fullName: "",
        email: "",
        phone: "",
        status: "ACTIVE",
        password: "",
        confirm: "",
        resetPassword: false,
    };
}

/** ========= Quyền (inline) ========= **/
const PERM_GROUPS = [
    { title: "Quản lý khách hàng", icon: "👥", items: [
            ["CUSTOMER_READ", "Xem danh sách khách hàng"],
            ["CUSTOMER_CREATE", "Tạo khách hàng mới"],
            ["CUSTOMER_UPDATE", "Chỉnh sửa thông tin khách hàng"],
            ["CUSTOMER_DELETE", "Xóa khách hàng"],
        ]},
    { title: "Quản lý hợp đồng", icon: "🧾", items: [
            ["CONTRACT_READ", "Xem danh sách hợp đồng"],
            ["CONTRACT_CREATE", "Tạo hợp đồng mới"],
            ["CONTRACT_UPDATE", "Chỉnh sửa hợp đồng"],
            ["CONTRACT_APPROVE", "Phê duyệt hợp đồng"],
        ]},
    { title: "Quản lý thanh toán", icon: "💰", items: [
            ["PAYMENT_READ", "Xem thông tin thanh toán"],
            ["PAYMENT_CREATE", "Tạo phiếu thu"],
            ["PAYMENT_MARK_PAID", "Phê duyệt thanh toán"],
            ["PAYMENT_DELETE", "Xóa phiếu (chưa thanh toán)"],
        ]},
    { title: "Báo cáo & Thống kê", icon: "📊", items: [
            ["REPORT_VIEW", "Xem báo cáo tổng hợp"],
            ["REPORT_EXPORT", "Xuất báo cáo"],
            ["REPORT_FINANCE_VIEW", "Xem báo cáo tài chính"],
        ]},
    { title: "Quản trị hệ thống", icon: "⚙️", items: [
            ["USER_MANAGE", "Quản lý người dùng"],
            ["SYSTEM_CONFIG", "Cấu hình hệ thống"],
            ["SYSTEM_AUDIT_VIEW", "Xem nhật ký hệ thống"],
        ]},
];

const QUICK_PRESETS = {
    ADMIN: "ALL",
    SALES: [
        "CUSTOMER_READ", "CUSTOMER_CREATE", "CUSTOMER_UPDATE",
        "CONTRACT_READ", "CONTRACT_CREATE", "CONTRACT_UPDATE",
        "PAYMENT_READ", "PAYMENT_CREATE",
    ],
    ACCOUNTANT: [
        "CONTRACT_READ",
        "PAYMENT_READ", "PAYMENT_MARK_PAID",
        "REPORT_VIEW", "REPORT_FINANCE_VIEW",
    ],
};

async function fetchAllPermissions() {
    try {
        const { data } = await api.get("/api/roles/permissions");
        return Array.isArray(data) ? data : [];
    } catch {
        const all = new Set();
        PERM_GROUPS.forEach(g => g.items.forEach(([c]) => all.add(c)));
        return Array.from(all);
    }
}
async function createCustomRole(name, permissions) {
    const { data } = await api.post("/api/roles", { name, permissions });
    return data;
}

/** ========= Permission Picker ========= **/
function PermissionPicker({ initialRole = "SALES", initialPerms = [], onChange }) {
    const [allPerms, setAllPerms] = useState([]);
    const [mode, setMode] = useState(initialRole);   // ADMIN / SALES / ACCOUNTANT / CUSTOM
    const [picked, setPicked] = useState(new Set(initialPerms));

    useEffect(() => {
        (async () => {
            const list = await fetchAllPermissions();
            setAllPerms(list);
            const preset = QUICK_PRESETS[initialRole];
            if (preset === "ALL") setPicked(new Set(list));
            else if (preset) setPicked(new Set(preset));
            onChange?.({ mode: initialRole, roleName: initialRole, permissions: Array.from(preset === "ALL" ? list : (preset || [])) });
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        if (!allPerms.length) return;
        if (mode === "CUSTOM") {
            onChange?.({ mode: "CUSTOM", roleName: "CUSTOM", permissions: Array.from(picked) });
            return;
        }
        const preset = QUICK_PRESETS[mode];
        const perms = preset === "ALL" ? allPerms : (preset || []);
        setPicked(new Set(perms));
        onChange?.({ mode, roleName: mode, permissions: Array.from(perms) });
    }, [mode]); // eslint-disable-line

    const readOnly = mode !== "CUSTOM";
    const toggle = (code) => {
        if (readOnly) return;
        const next = new Set(picked);
        next.has(code) ? next.delete(code) : next.add(code);
        setPicked(next);
        onChange?.({ mode: "CUSTOM", roleName: "CUSTOM", permissions: Array.from(next) });
    };

    return (
        <div className="space-y-3">
            <div className="font-semibold text-slate-700">🔒 Phân quyền chi tiết</div>

            {/* Presets */}
            <div className="flex gap-2 flex-wrap">
                {["ADMIN", "SALES", "ACCOUNTANT", "CUSTOM"].map(r => (
                    <button
                        key={r}
                        type="button"
                        onClick={() => setMode(r)}
                        className={`px-3 py-1.5 rounded-lg border text-sm ${mode===r ? "bg-indigo-600 text-white border-indigo-600" : "bg-white hover:bg-slate-50"}`}
                    >
                        {r === "CUSTOM" ? "Tùy chỉnh" : r}
                    </button>
                ))}
            </div>

            {/* Groups */}
            <div className="grid grid-cols-1 gap-3">
                {PERM_GROUPS.map((g, i) => (
                    <div key={i} className="rounded-xl border border-indigo-100 bg-white shadow p-3">
                        <div className="font-medium mb-2">{g.icon} {g.title}</div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                            {g.items.map(([code, label]) => {
                                const disabled = readOnly || !allPerms.includes(code);
                                const checked = picked.has(code);
                                return (
                                    <label key={code} className={`flex items-center gap-2 ${disabled ? "opacity-60" : ""}`}>
                                        <input type="checkbox" disabled={disabled} checked={checked} onChange={() => toggle(code)} />
                                        <span>{label}</span>
                                    </label>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>

            {mode === "CUSTOM" && (
                <p className="text-xs text-slate-500">
                    Khi lưu, hệ thống sẽ tạo một <b>vai trò mới</b> từ các quyền đã chọn và gán cho người dùng.
                </p>
            )}
        </div>
    );
}

/** ========= Trang Users ========= **/
export default function Users() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // filters ở list
    const [q, setQ] = useState("");
    const dq = useDebounce(q, 450);
    const [role, setRole] = useState("");
    const [status, setStatus] = useState("");

    // modal
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState(emptyForm());

    // permission state từ picker
    const [permState, setPermState] = useState({ mode: "SALES", roleName: "SALES", permissions: [] });

    useEffect(() => { load(); }, [page, dq, role, status]); // eslint-disable-line

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/users", {
                params: { q: dq || undefined, role: role || undefined, status: status || undefined, page, size: PAGE_SIZE, sort: "id,desc" },
            });
            const { list, pages } = normalizePage(data);
            setRows(list.map((u) => ({
                id: u.id,
                username: u.username,
                fullName: u.fullName || u.name || "",
                email: u.email || "",
                phone: u.phone || "",
                role: (u.role || "").toString().replace(/^ROLE_/, "") || "SALES",
                status: u.active === false ? "INACTIVE" : "ACTIVE",
            })));
            setTotalPages(pages);
        } catch (e) {
            console.error(e); setRows([]); setTotalPages(1);
        } finally { setLoading(false); }
    }

    function openCreate() {
        setEditing(null);
        setForm(emptyForm());
        setPermState({ mode: "SALES", roleName: "SALES", permissions: [] }); // mặc định SALES
        setShow(true);
    }
    function openEdit(row) {
        setEditing(row);
        setForm({
            username: row.username || "",
            fullName: row.fullName || "",
            email: row.email || "",
            phone: row.phone || "",
            status: row.status || "ACTIVE",
            password: "",
            confirm: "",
            resetPassword: false,
        });
        setPermState({ mode: row.role || "SALES", roleName: row.role || "SALES", permissions: [] });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();
        try {
            // lấy roleName từ permState
            let roleNameToUse = permState?.roleName || "SALES";
            if (permState?.mode === "CUSTOM") {
                if (!permState?.permissions?.length) { alert("Chọn ít nhất một quyền cho vai trò tùy chỉnh."); return; }
                try {
                    const name = `CUSTOM_${Date.now()}`;
                    const created = await createCustomRole(name, permState.permissions);
                    roleNameToUse = created?.name || name;
                } catch {
                    alert("Backend chưa hỗ trợ tạo Role tùy chỉnh (/api/roles)."); return;
                }
            }

            if (!editing) {
                if (!form.password?.trim()) { alert("Mật khẩu không được để trống"); return; }
                if (form.password !== form.confirm) { alert("Xác nhận mật khẩu không khớp"); return; }
                const payload = {
                    username: form.username?.trim(),
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    password: form.password,
                    roleName: roleNameToUse,
                    active: form.status === "ACTIVE",
                };
                await api.post("/api/users", payload);
            } else {
                const payload = {
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    roleName: roleNameToUse,
                    active: form.status === "ACTIVE",
                };
                if (form.resetPassword) {
                    if (!form.password?.trim()) { alert("Nhập mật khẩu mới"); return; }
                    if (form.password !== form.confirm) { alert("Xác nhận mật khẩu không khớp"); return; }
                    payload.password = form.password;
                }
                await api.put(`/api/users/${editing.id}`, payload);
            }
            setShow(false);
            if (rows.length === 0 && page > 0) setPage((p) => p - 1);
            await load();
            alert(editing ? "Đã cập nhật người dùng" : "Đã tạo người dùng");
        } catch (err) {
            const msg = err?.response?.data?.message || err?.response?.data?.error || "Lưu người dùng thất bại";
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá người dùng ${row.username}?`)) return;
        try {
            await api.delete(`/api/users/${row.id}`);
            if (rows.length === 1 && page > 0) setPage((p) => p - 1);
            else await load();
            alert("Đã xoá");
        } catch (err) {
            const msg = err?.response?.data?.message || err?.response?.data?.error || "Xoá người dùng thất bại";
            alert(msg);
        }
    }

    return (
        <div className="space-y-4">
            {/* Header + Filters (giữ nguyên) */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">Quản trị viên có thể quản lý người dùng</p>
                </div>
                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow w-64"
                            placeholder="Tên đăng nhập / Họ tên / Email / SĐT…"
                            value={q}
                            onChange={(e) => { setQ(e.target.value); setPage(0); }}
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Vai trò</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={role}
                            onChange={(e) => { setRole(e.target.value); setPage(0); }}
                        >
                            <option value="">Tất cả</option>
                            {ROLES.map((r) => <option key={r} value={r}>{r}</option>)}
                        </select>
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={status}
                            onChange={(e) => { setStatus(e.target.value); setPage(0); }}
                        >
                            <option value="">Tất cả</option>
                            {STATUSES.map((s) => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>
                    <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 ml-auto">
                        Thêm người dùng
                    </button>
                </div>
            </div>

            {/* Bảng */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên đăng nhập</th>
                            <th className="px-4 py-3 text-left">Họ tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Chưa có dữ liệu</td></tr>
                        ) : rows.map((u) => (
                            <tr key={u.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{u.username}</td>
                                <td className="px-4 py-3">{u.fullName || "-"}</td>
                                <td className="px-4 py-3">{u.email || "-"}</td>
                                <td className="px-4 py-3">{u.phone || "-"}</td>
                                <td className="px-4 py-3">{u.role}</td>
                                <td className="px-4 py-3">
                    <span className={"px-2 py-0.5 rounded-full text-xs " + (u.status === "ACTIVE" ? "bg-emerald-100 text-emerald-700" : "bg-slate-100 text-slate-700")}>
                      {u.status}
                    </span>
                                </td>
                                <td className="px-4 py-3 text-right">
                                    <div className="inline-flex gap-2">
                                        <button onClick={() => openEdit(u)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                        <button onClick={() => remove(u)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 justify-center">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => Math.max(0, p - 1))} disabled={page <= 0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => p + 1)} disabled={page + 1 >= totalPages}>Sau →</button>
            </div>

            {/* Modal (scrollable, footer cố định) */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl max-h-[90vh] bg-white rounded-2xl shadow-xl border border-indigo-100 flex flex-col">
                        {/* Header */}
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa người dùng" : "Thêm người dùng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>Đóng</button>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-5">
                            <form id="userForm" onSubmit={save} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm text-slate-600">Tên đăng nhập</label>
                                    <input required disabled={!!editing} value={form.username}
                                           onChange={(e) => setForm((f) => ({ ...f, username: e.target.value }))}
                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                                </div>
                                <div>
                                    <label className="text-sm text-slate-600">Họ tên</label>
                                    <input required value={form.fullName}
                                           onChange={(e) => setForm((f) => ({ ...f, fullName: e.target.value }))}
                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                                </div>
                                <div>
                                    <label className="text-sm text-slate-600">Email</label>
                                    <input required type="email" value={form.email}
                                           onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                                </div>
                                <div>
                                    <label className="text-sm text-slate-600">Điện thoại</label>
                                    <input value={form.phone}
                                           onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))}
                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                                </div>
                                <div>
                                    <label className="text-sm text-slate-600">Trạng thái</label>
                                    <select value={form.status}
                                            onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                        {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                                    </select>
                                </div>

                                {/* Mật khẩu */}
                                {!editing ? (
                                    <>
                                        <div>
                                            <label className="text-sm text-slate-600">Mật khẩu</label>
                                            <input type="password" value={form.password}
                                                   onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                                   className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" required />
                                        </div>
                                        <div>
                                            <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                            <input type="password" value={form.confirm}
                                                   onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                                   className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" required />
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        <div className="md:col-span-2 flex items-center gap-2">
                                            <input id="resetPw" type="checkbox" checked={form.resetPassword}
                                                   onChange={(e) => setForm((f) => ({ ...f, resetPassword: e.target.checked }))} />
                                            <label htmlFor="resetPw" className="text-sm text-slate-600 select-none">Đặt mật khẩu mới</label>
                                        </div>
                                        {form.resetPassword && (
                                            <>
                                                <div>
                                                    <label className="text-sm text-slate-600">Mật khẩu mới</label>
                                                    <input type="password" value={form.password}
                                                           onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" required />
                                                </div>
                                                <div>
                                                    <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                                    <input type="password" value={form.confirm}
                                                           onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                                           className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" required />
                                                </div>
                                            </>
                                        )}
                                    </>
                                )}

                                {/* Phân quyền chi tiết — KHÔNG còn dropdown Vai trò */}
                                <div className="md:col-span-2">
                                    <PermissionPicker
                                        initialRole={editing?.role || "SALES"}
                                        onChange={(st) => setPermState(st)}
                                    />
                                </div>
                            </form>
                        </div>

                        {/* Footer cố định */}
                        <div className="p-4 border-t flex justify-end gap-2">
                            <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={() => setShow(false)}>
                                Huỷ
                            </button>
                            <button form="userForm" className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                Lưu
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
